"use strict";parserFactory.register("rainofsnow.com",()=>new RainOfSnowParser);class RainOfSnowParser extends Parser{constructor(){super()}async getChapterUrls(e,r){return this.getChapterUrlsFromMultipleTocPages(e,RainOfSnowParser.extractPartialChapterList,RainOfSnowParser.getUrlsOfTocPages,r)}static extractPartialChapterList(e){return[...e.querySelectorAll("div#chapter a:not(.page-numbers)")].map(e=>util.hyperLinkToChapter(e))}static getUrlsOfTocPages(e){return[...e.querySelectorAll("ul.page-numbers a.page-numbers:not(.next)")].map(e=>e.href)}findContent(e){let r=e.querySelector("div.zoomdesc-cont");return util.fixDelayLoadedImages(r,"data-src"),r}extractTitleImpl(e){return e.querySelector(".container h2")}findChapterTitle(e){return e.querySelector("li.menu-toc-current")?.textContent??null}findCoverImageUrl(e){let r=e.querySelector(".imagboca1 img");return r?.getAttribute("data-src")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("#synop")]}}